sql:
SELECT player, AVG(time_spent) AS average_time_spent
FROM game_performance_metrics
GROUP BY player;

SELECT player, AVG(score_of_abapro_reimplementation) AS average_score
FROM game_performance_metrics
WHERE player = 'AbaProReimplementation';

SELECT MAX(score_of_papadopoulos_reimplementation) AS max_score
FROM game_performance_metrics
WHERE player = 'PapadopoulosReimplementation' AND version_id = 2;

SELECT COUNT(*) AS total_reports
FROM analytic_reports
WHERE user_id = 0;

SELECT name
FROM game_implementations
WHERE description LIKE '%Reimplementation%';

external_knowledge:
- A game version is considered to have at least one game state if it has a corresponding entry in the game_states table; 
- The average scores are calculated based on the scores achieved by AbaPro Reimplementation and Papadopoulos Reimplementation in the game_performance_metrics table; 
- The game versions are ordered first by the average AbaPro score in descending order, and then by the average Papadopoulos score in descending order in case of a tie in the average AbaPro score.

sql:
SELECT username
FROM users
WHERE user_id IN (
  SELECT user_id
  FROM analytic_reports
);

SELECT version_number, release_date
FROM game_versions
ORDER BY release_date DESC;
